  name = EXCLUDED.name,
  legal_name = EXCLUDED.legal_name,
  cnpj = COALESCE(EXCLUDED.cnpj, public.insurance_operators.cnpj),
  brand_group = EXCLUDED.brand_group,
  modality = EXCLUDED.modality,
  address_street = EXCLUDED.address_street,
  address_number = EXCLUDED.address_number,
  address_complement = EXCLUDED.address_complement,
  address_district = EXCLUDED.address_district,
  address_city = EXCLUDED.address_city,
  address_state = EXCLUDED.address_state,
  address_zip = EXCLUDED.address_zip,
  phone_area_code = EXCLUDED.phone_area_code,
  contact_phone = COALESCE(public.insurance_operators.contact_phone, EXCLUDED.contact_phone),
  fax = EXCLUDED.fax,
  contact_email = COALESCE(public.insurance_operators.contact_email, EXCLUDED.contact_email),
  responsible_name = COALESCE(public.insurance_operators.responsible_name, EXCLUDED.responsible_name),
  representative_role = EXCLUDED.representative_role,
  ans_registered_at = EXCLUDED.ans_registered_at,
  is_active = true,
  updated_at = now()
WHERE public.insurance_operators.is_platform_account = false;
